#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n; scanf("%d",&n);
        int *h = (int*)malloc(n*sizeof(int));
        for(int i=0;i<n;++i) scanf("%d",&h[i]);
        int *dp = (int*)malloc(n*sizeof(int));
        dp[0]=0;
        if(n>1) dp[1]=abs(h[1]-h[0]);
        for(int i=2;i<n;++i){
            int cost1 = dp[i-1] + abs(h[i]-h[i-1]);
            int cost2 = dp[i-2] + abs(h[i]-h[i-2]);
            dp[i] = cost1<cost2?cost1:cost2;
        }
        printf("%d\n", dp[n-1]);
        free(h);
        free(dp);
    }
    return 0;
}

