import java.io.*;
import java.util.*;
public class Main{
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out=new StringBuilder();
        int T=Integer.parseInt(br.readLine().trim());
        while(T-- > 0){
            int n=Integer.parseInt(br.readLine().trim());
            int[] h=new int[n];
            StringTokenizer st=new StringTokenizer(br.readLine());
            for(int i=0;i<n;i++) h[i]=Integer.parseInt(st.nextToken());
            int[] dp=new int[n];
            dp[0]=0;
            if(n>1) dp[1]=Math.abs(h[1]-h[0]);
            for(int i=2;i<n;i++){
                int cost1=dp[i-1]+Math.abs(h[i]-h[i-1]);
                int cost2=dp[i-2]+Math.abs(h[i]-h[i-2]);
                dp[i]=Math.min(cost1,cost2);
            }
            out.append(dp[n-1]).append('\n');
        }
        System.out.print(out.toString());
    }
}

