const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
const T=Number(input[idx++]);
let outputs=[];
function minJumpEnergy(heights){
  const n=heights.length;
  const dp=new Array(n).fill(0);
  if(n>1) dp[1]=Math.abs(heights[1]-heights[0]);
  for(let i=2;i<n;i++){
    const cost1=dp[i-1]+Math.abs(heights[i]-heights[i-1]);
    const cost2=dp[i-2]+Math.abs(heights[i]-heights[i-2]);
    dp[i]=cost1<cost2?cost1:cost2;
  }
  return dp[n-1];
}
for(let t=0;t<T;t++){
  const n=Number(input[idx++]);
  const heights=[];
  for(let i=0;i<n;i++) heights.push(Number(input[idx++]));
  outputs.push(String(minJumpEnergy(heights)));
}
